def test_exponential_decay():
    Gamma0 = 1.0
    lambda_val = 0.5

    for t in np.linspace(0, 10, 100):
        Gamma_t = Gamma0 * np.exp(-lambda_val * t)
        assert Gamma_t <= Gamma0 + 1e-10
        assert Gamma_t >= 0
        if t > 0:
            assert Gamma_t < Gamma0
